DROP DATABASE IF EXISTS hr_training;
CREATE DATABASE hr_training CHARACTER SET utf8mb4;
USE hr_training;

CREATE TABLE locations (
    location_id     INT PRIMARY KEY AUTO_INCREMENT,
    city            VARCHAR(100) NOT NULL,
    state           VARCHAR(100),
    country         VARCHAR(100) NOT NULL
);

CREATE TABLE departments (
    department_id   INT PRIMARY KEY AUTO_INCREMENT,
    department_name VARCHAR(100) NOT NULL,
    location_id     INT,
    budget          DECIMAL(14,2),
    FOREIGN KEY (location_id) REFERENCES locations(location_id)
);

CREATE TABLE jobs (
    job_id          INT PRIMARY KEY AUTO_INCREMENT,
    job_title       VARCHAR(100) NOT NULL,
    job_grade       VARCHAR(10),
    min_salary      DECIMAL(10,2),
    max_salary      DECIMAL(10,2)
);

CREATE TABLE employees (
    employee_id       INT PRIMARY KEY AUTO_INCREMENT,
    first_name        VARCHAR(50) NOT NULL,
    last_name         VARCHAR(50) NOT NULL,
    email             VARCHAR(150) UNIQUE,
    phone             VARCHAR(30),
    date_of_birth     DATE,
    gender            VARCHAR(10),
    hire_date         DATE NOT NULL,
    job_id            INT,
    department_id     INT,
    manager_id        INT,
    salary            DECIMAL(10,2) NOT NULL,
    commission_pct    DECIMAL(5,2) DEFAULT 0,
    employment_status VARCHAR(20) DEFAULT 'Active',
    termination_date  DATE,
    FOREIGN KEY (job_id) REFERENCES jobs(job_id),
    FOREIGN KEY (department_id) REFERENCES departments(department_id),
    FOREIGN KEY (manager_id) REFERENCES employees(employee_id)
);

CREATE TABLE salary_history (
    salary_history_id INT PRIMARY KEY AUTO_INCREMENT,
    employee_id       INT NOT NULL,
    old_salary        DECIMAL(10,2),
    new_salary        DECIMAL(10,2),
    change_date       DATE NOT NULL,
    change_reason     VARCHAR(100),
    FOREIGN KEY (employee_id) REFERENCES employees(employee_id)
);

CREATE TABLE performance_reviews (
    review_id     INT PRIMARY KEY AUTO_INCREMENT,
    employee_id   INT NOT NULL,
    reviewer_id   INT,
    review_date   DATE NOT NULL,
    rating        INT NOT NULL,
    comments      VARCHAR(255),
    FOREIGN KEY (employee_id) REFERENCES employees(employee_id),
    FOREIGN KEY (reviewer_id) REFERENCES employees(employee_id)
);

CREATE TABLE projects (
    project_id      INT PRIMARY KEY AUTO_INCREMENT,
    project_name    VARCHAR(150) NOT NULL,
    department_id   INT,
    start_date      DATE,
    end_date        DATE,
    budget          DECIMAL(14,2),
    status          VARCHAR(20),
    FOREIGN KEY (department_id) REFERENCES departments(department_id)
);

CREATE TABLE employee_projects (
    employee_id     INT NOT NULL,
    project_id      INT NOT NULL,
    role            VARCHAR(100),
    hours_allocated INT,
    PRIMARY KEY (employee_id, project_id),
    FOREIGN KEY (employee_id) REFERENCES employees(employee_id),
    FOREIGN KEY (project_id) REFERENCES projects(project_id)
);

CREATE TABLE leave_requests (
    leave_id        INT PRIMARY KEY AUTO_INCREMENT,
    employee_id     INT NOT NULL,
    leave_type      VARCHAR(30),
    start_date      DATE NOT NULL,
    end_date        DATE NOT NULL,
    days_requested  INT,
    status          VARCHAR(20),
    FOREIGN KEY (employee_id) REFERENCES employees(employee_id)
);

CREATE TABLE attendance (
    attendance_id   BIGINT PRIMARY KEY AUTO_INCREMENT,
    employee_id     INT NOT NULL,
    work_date       DATE NOT NULL,
    check_in        TIME,
    check_out       TIME,
    status          VARCHAR(20),
    FOREIGN KEY (employee_id) REFERENCES employees(employee_id)
);



























































-- Indexes to support Week 4 query optimization exercises
CREATE INDEX idx_employees_department ON employees(department_id);
CREATE INDEX idx_employees_manager ON employees(manager_id);
CREATE INDEX idx_attendance_employee_date ON attendance(employee_id, work_date);
CREATE INDEX idx_salary_history_employee ON salary_history(employee_id);
CREATE INDEX idx_reviews_employee ON performance_reviews(employee_id);
